import {IonIcon} from '@ionic/react';
import Link from '../../components/Link';
const _blighted_myrmidon = {title: "Blighted Myrmidon", jsx: <><h2 id="arc-antipaladin-blighted_myrmidon-blighted-myrmidon">Blighted Myrmidon</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 91</Link><br/>Blighted myrmidons carry the seed of rot in their black hearts and sap life from the natural world.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-blighted_myrmidon-smite-nature-su" data-hash-target><div className="box">Smite Nature (Su)</div><div className="flavor">A blighted myrmidon can drain the life from a creature tied to nature.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Smite good</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Swift Action</div></div><div className="abEnd"><div className="box">The blighted myrmidon chooses one target within sight to smite. Regardless of its alignment, if the target is an animal, plant, or vermin, the blighted myrmidon adds her Charisma bonus (if any) on her attack rolls and adds her blighted myrmidon level on damage rolls against the target of her <em>smite.</em> If the target of <em>smite nature</em> is an elemental, a fey, or a creature with levels of druid, hunter, ranger, or shifter, the bonus on damage on the first successful attack increases to 2 points of damage per class level the blighted myrmidon has. This ability otherwise functions as smite good.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-blighted_myrmidon-corrupted-companion-sp" data-hash-target><div className="box">Corrupted Companion (Sp)</div><div className="flavor">A blighted myrmidon can call upon a corrupted servant of nature.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Fiendish boon</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">When the blighted myrmidon chooses the second <em>fiendish boon</em> option, it functions as a <Link to="/spell/summon_natures_ally">summon nature's ally</Link> spell of the appropriate level. This ability otherwise functions as the standard fiendish boon antipaladin class feature.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-blighted_myrmidon-feed-on-decay-ex" data-hash-target><div className="box">Feed on Decay (Ex)</div><div className="flavor">A blighted myrmidon draws strength from corrupting the natural world.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">10th-level use of smite good</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 10th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When the blighted myrmidon damages a creature with her <em>smite nature</em> ability, she gains a +1 morale bonus on attack rolls, damage rolls, and saving throws for 1 round.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-blighted_myrmidon-aura-of-decay-su" data-hash-target><div className="box">Aura of Decay (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of vengeance</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Free Action</div></div><div className="abEnd"><div className="box">A blighted myrmidon can expend two uses of her <em>smite nature</em> ability to generate an aura of decay with a range of 10 feet for 1 minute. Living foes of the blighted myrmidon within the aura take 3d6 points of damage unless they succeed at a Fortitude save (DC = <Link to="/misc/half">half</Link> the blighted myrmidon's level + her Charisma modifier) for half damage. If an elemental, a fey, or a creature with levels in druid, hunter, ranger, or shifter takes damage from aura of decay, the blighted myrmidon regains a number of hit points equal to half the amount of damage the creature takes; this doesn't stack if multiple such creatures are in the aura.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-blighted_myrmidon-enervating-touch-su" data-hash-target><div className="box">Enervating Touch (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The cruelty gained at 15th level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 15th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When she damages a creature with her <em>touch of corruption,</em> a blighted myrmidon can suppress the vital force of her target for 1 round per level. While affected, when the target regains hit points, it regains only half the number of hit points it would otherwise receive, and it can't gain <Link to="/rule/temporary_hit_points">temporary hit points</Link>. The target can attempt a Fortitude save (DC = half the blighted myrmidon's level + her Charisma modifier) to negate this effect.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-blighted_myrmidon-unnatural-champion-ex" data-hash-target><div className="box">Unnatural Champion (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Unholy champion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When a blighted myrmidon uses <em>smite nature</em> and strikes an elemental or fey creature with the <Link to="/subtype/extraplanar">extraplanar</Link> subtype, the target is also subject to the effects of a <Link to="/spell/banishment">banishment</Link> spell, using her blighted myrmidon level as her caster level, and her weapon and unholy symbol automatically count as objects that the subject hates. This ability otherwise functions as <em>unholy champion.</em></div></div></div></div>
</>};
const _dread_vanguard = {title: "Dread Vanguard", jsx: <><h2 id="arc-antipaladin-dread_vanguard-dread-vanguard">Dread Vanguard</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption pg. 22</Link><br/>Some antipaladins serve or ally themselves with villains who are bent on earthly conquest. They care nothing for the intricacies of divine spellcasting, but malevolent energy still surrounds them. Whether alone or at the head of a marauding host, these cruel warriors bring suffering and death - but their presence also heralds the coming of a greater evil.</p>
<p>Dread vanguards have the following class features.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-dread_vanguard-beacon-of-evil-su" data-hash-target><div className="box">Beacon of Evil (Su)</div><div className="flavor">A dread vanguard unleashes the powers of his vile masters to strengthen both himself and his allies.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Spells</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A dread vanguard gains one additional use of his <em>touch of corruption</em> ability per day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">He can spend a use of his <em>touch of corruption</em> ability to manifest the darkness in his soul as an area of flickering shadows with a 30-foot radius centered on him. These shadows don't affect visibility. The antipaladin and all allies in the area gain a +1 morale bonus to AC and on attack rolls, damage rolls, and saving throws against fear, and also ignore the first 5 points of hardness when attacking unattended inanimate objects. This lasts for 1 minute, as long as the dread vanguard is conscious.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">The dread vanguard now gains two additional uses of his <em>touch of corruption</em> ability per day. The <em>beacon of evil</em> aura grants <Link to="/umr/fast_healing">fast healing</Link> 3 to the dread vanguard as well as to his allies while they remain within it. Additionally, while this aura is active, the antipaladin can use his <em>touch of corruption</em> ability against any targets within its radius by making a ranged touch attack.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 12th Level</div></div><div className="abEnd"><div className="box">The dread vanguard now gains three additional uses of his <em>touch of corruption</em> ability per day. When he activates <em>beacon of evil,</em> a dread vanguard can choose to increase the radius of one antipaladin aura he possesses to 30 feet. Also, the morale bonus granted to AC and on attack rolls, damage rolls, and saving throws against fear increases to +2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">The dread vanguard now gains four additional uses of his <em>touch of corruption</em> ability per day. The fast healing granted by <em>beacon of evil</em> increases to 5. Additionally, the antipaladin's weapons and those of his allies within the aura's radius are considered evil for the purpose of overcoming damage reduction.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 20th Level</div></div><div className="abEnd"><div className="box">The dread vanguard now gains five additional uses of his <em>touch of corruption</em> ability per day. The <em>beacon of evil's</em> radius increases to 60 feet, and the morale bonus granted to AC and on attack rolls, damage rolls, and saving throws against fear increases to +4. Lastly, attacks made by the dread vanguard and his allies within the aura's radius are infused with pure unholy power, and deal an additional 1d6 points of damage.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">A dread vanguard does not gain any spells or spellcasting abilities, cannot use spell trigger or spell completion magic items, and does not have a caster level from this class.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-dread_vanguard-dark-emissary-sp" data-hash-target><div className="box">Dark Emissary (Sp)</div><div className="flavor">A dread vanguard becomes a true messenger of the forces of darkness he serves.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of sin</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 14th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">Allies or evil creatures who serve the same power or organization as the dread vanguard are immune to the <em>crushing despair</em> and symbol effects, and automatically know that the location has been marked for their masters. They can treat this location as very familiar for the purpose of <Link to="/spell/teleport">teleport</Link> and similar spells and can use <Link to="/spell/scrying">scrying</Link> and related spells as though they were familiar with any subject within 20 feet of it.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Once per day, the dread vanguard can expend two uses of his <em>touch of corruption</em> ability to mark one location within 60 feet with the stain of evil. This location can be any point in space, but the ability works best if placed on an altar, shrine, or other site important to a community. The location is affected as if by a <Link to="/spell/desecrate">desecrate</Link> spell. Creatures approaching within 30 feet of the site must succeed at a Will save or suffer the effects of <Link to="/spell/crushing_despair">crushing despair</Link>. Marking a new site ends all effects on the previous site.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">The dread vanguard can also mark the site with a <Link to="/spell/symbol_of_pain">symbol of pain</Link>, and can mark two sites simultaneously. If he marks a third, all effects on the oldest active site end.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 20th Level</div></div><div className="abEnd"><div className="box">The dread vanguard can also mark the site wity a <Link to="/spell/symbol_of_weakness">symbol of weakness</Link>, and can mark three sites simultaneously. If he marks a fourth, all effects on the oldest active site end.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">If available, all three of these effects overlap. Creatures must save against each effect individually, and the effects stack. The caster level for all effects is equal to the dread vanguard's class level. The save DC is equal to 10 + <Link to="/misc/half">half</Link> the antipaladin's level + his Charisma modifier. A location remains marked in this way for up to 1 day per antipaladin level. During this time, the <em>crushing despair</em> and <em>symbols</em> are triggered when the first target enters each spell's area. They remain active for 10 minutes, then can be triggered again if targets are within range. If the effects are disabled, they become inactive for 10 minutes, but then can be triggered again as normal. <Link to="/spell/dispel_magic">Dispel magic</Link> and similar spells suppress the effects, and all effects of dark emissary can be removed by a <Link to="/spell/consecrate">consecrate</Link> spell cast on the location by a cleric of a level equal to or higher than the dread vanguard.</div></div></div></div>
</>};
const _fearmonger = {title: "Fearmonger", jsx: <><h2 id="arc-antipaladin-fearmonger-fearmonger">Fearmonger</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 20</Link><br/>The fearmonger wants to do more than cause pain, misery, and confusion. He wishes to spread fear among his foes and infect entire populations with it. The fearmonger archetype is available only to the antipaladin alternate class.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-fearmonger-feed-on-fear-su" data-hash-target><div className="box">Feed on Fear (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch of corruption</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">A number of times per day equal to <Link to="/misc/half">half</Link> his antipaladin level plus his Charisma bonus.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">The first time in a round a creature fails a saving throw against a fear effect created by a fearmonger's spell, spell-like ability, or supernatural ability (including any ability that causes a creature to be shaken, frightened, or panicked), the fearmonger is healed of 1 point of damage per 2 antipaladin levels. If the fearmonger is at full hit points when this ability is activated, he instead gains an equal number of <Link to="/rule/temporary_hit_points">temporary hit points</Link>. These temporary hit points last for 1 minute. Temporary hit points gained through multiple successful uses of this ability do not stack; the duration increases instead.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-fearmonger-frightening-cruelty-su" data-hash-target><div className="box">Frightening Cruelty (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">The fearmonger must select <Link to="/misc/shaken">shaken</Link> as his 3rd-level cruelty.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">He must choose <Link to="/misc/dazed">dazed</Link> as his 6th-level cruelty.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">He must select <Link to="/misc/frightened">frightened</Link> as his 9th-level cruelty.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 12th Level</div></div><div className="abEnd"><div className="box">The fearmonger gains the <em>panicked</em> cruelty.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-fearmonger-panicked" data-hash-target><div className="box">Panicked</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Cruelty</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The target is <Link to="/misc/panicked">panicked</Link> for 1 round per 4 class levels the antipaladin possesses. The antipaladin must have the <em>shaken</em> and <em>frightened</em> cruelties before selecting this cruelty.</div></div></div></div>
</>};
const _insinuator = {title: "Insinuator", jsx: <><h2 id="arc-antipaladin-insinuator-insinuator">Insinuator</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 20</Link><br/>Between the selfless nobility of paladins and the chaotic menace of antipaladins, there exists a path of dedicated self-interest. Shunning the ties that bind them to a single deity, insinuators embrace whatever forces help them achieve their own agenda and glory, borrowing power to emulate divine warriors.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-alignment" data-hash-target><div className="box">Alignment</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An insinuator can be lawful evil, neutral evil, or chaotic evil.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-code-of-conduct" data-hash-target><div className="box">Code of Conduct</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An insinuator must always work toward his own self-interest, enrichment, or glory, and must also abide by the moral strictures of whatever outsider they have chosen to invoke that day (see invocation below). If the insinuator breaks an invoked outsider's code, he cannot invoke outsiders of that same alignment until he seeks <Link to="/spell/atonement">atonement</Link>, although outsiders of other alignments may still heed his call.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-invocation-ex" data-hash-target><div className="box">Invocation (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of evil</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">At the start of each day, an insinuator can meditate for 10 minutes to contact and barter with an outsider to empower him for a day. An insinuator can freely invoke an outsider of his own alignment. He can instead invoke an outsider within one step of his own alignment by succeeding at a Diplomacy or Knowledge (religion) skill check (DC = 15 + the insinuator's antipaladin level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">While invoking the power of an outsider, the insinuator radiates an alignment aura that matches that of the outsider's, and becomes vulnerable to alignment-based effects that target that outsider's alignment (such as <em>smite evil</em> or <Link to="/spell/chaos_hammer">chaos hammer</Link>). None of an insinuator's supernatural or spell-like class abilities function unless he has invoked the power of an outsider, and the alignment of the being invoked may affect how some abilities function.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-detect-balance-sp" data-hash-target><div className="box">Detect Balance (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Detect good</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">At will, an insinuator can detect strong moral leanings. This functions as <Link to="/spell/detect_evil">detect evil</Link> or <Link to="/spell/detect_good">detect good</Link>, but does not actually reveal the target's alignment, only whether the target is neutral (rather than good or evil) and the relative strength of that aura.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-smite-impudence-su" data-hash-target><div className="box">Smite Impudence (Su)</div><div className="flavor">An insinuator can beseech the forces empowering him to punish their shared enemies.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Smite good</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">Once a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Swift Action</div></div><div className="abEnd"><div className="box">The insinuator chooses one target within sight to smite. An insinuator cannot use smite against a target that shares an alignment with the outsider he has invoked for the day. The insinuator adds his Charisma bonus on his attack rolls and <Link to="/misc/half">half</Link> his insinuator level on all damage rolls made against the target of his smite. If the target is an outsider, dragon, or divine spellcaster with an alignment opposed to that of the outsider he has invoked for the day, the bonus damage on the first successful attack increases to 1 point of damage per antipaladin level the insinuator has. Regardless of the target, the smite attack automatically bypasses any damage reduction the creature might possess. In addition, each time the insinuator declares a smite, he gains a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to his antipaladin level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 4th Level</div></div><div className="abEnd"><div className="box">The insinuator can smite twice a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">The insinuator can smite three times a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">The insinuator can smite fourt times a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">The insinuator can smite five times a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">The insinuator can smite six times a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">The insinuator can smite seven times a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The smite effect remains until the target is defeated or the next time the insinuator rests and regains his uses of this ability.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-selfish-healing-su" data-hash-target><div className="box">Selfish Healing (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch of corruption</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Swift Action</div></div><div className="abEnd"><div className="box">An insinuator can heal his wounds by touch. This is treated exactly like the paladin's <Link to="/ability/lay_on_hands">lay on hands</Link> class feature, except it can be used only to heal the insinuator and cannot be used on other creatures.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-aura-of-ego-su" data-hash-target><div className="box">Aura of Ego (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of cowardice</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An insinuator radiates an aura that bolsters allies and deters enemies. Each ally within 10 feet gains a +2 morale bonus on saving throws against fear effects. Enemies within 10 feet take a -2 penalty on saving throws against fear effects. This ability functions only while the insinuator is conscious, not if he is unconscious or dead.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-stubborn-health-ex" data-hash-target><div className="box">Stubborn Health (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Plague bringer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An insinuator takes only half damage from diseases and poisons, and none of his ability scores can be reduced below 1 by these effects.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-greeds-su" data-hash-target><div className="box">Greeds (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Cruelty</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An insinuator can heal himself of certain conditions. This functions as the <em>mercy</em> paladin class ability, but these <em>mercies</em> can only be applied to the insinuator himself.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-channel-energy-su" data-hash-target><div className="box">Channel Energy (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Channel negative energy</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">An insinuator can <Link to="/ability/channel_negative_energy">channel negative energy</Link>, treating his antipaladin level as his effective <Link to="/class/cleric">cleric</Link> level. If he invokes a neutral outsider for the day, he may instead chose during the invocation to channel positive energy, but treats his effective cleric level as half his antipaladin level. Using this ability consumes two uses of his selfish healing ability. This is a Charisma-based ability.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-bonus-feats" data-hash-target><div className="box">Bonus Feats</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Antipaladin spells</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An insinuator gains one bonus feat, which must be selected from the list of <Link to="/main/combat_feat">combat feats</Link> or <Link to="/feat/skill_focus">Skill Focus</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">You gain a new combat or Skill Focus feat.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">You gain a new combat or Skill Focus feat.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">You gain a new combat or Skill Focus feat.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">You gain a new combat or Skill Focus feat.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">You gain a new combat or Skill Focus feat.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-ambitious-bond-sp" data-hash-target><div className="box">Ambitious Bond (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An insinuator gains a divine bond with either a bonded weapon or an outsider servant. This functions as the antipaladin's <em>fiendish boon</em> with the following modifications.</div></div></div></div>
<div className="ability p subAbility numbered"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-bonded-weapon" data-hash-target><div className="box">Bonded Weapon</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">This functions as the antipaladin ability, except the first special ability added to a weapon must correspond to the alignment of the outsider the insinuator has invoked for that day: <Link to="/magic-enh/anarchic">anarchic</Link> (chaos), <Link to="/magic-enh/axiomatic">axiomatic</Link> (law), or <Link to="/magic-enh/unholy">unholy</Link> (evil). Additional special abilities may be applied if any equivalent bonus remains.</div></div></div></div>
<div className="ability p subAbility numbered"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-outsider-servant" data-hash-target><div className="box">Outsider Servant</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">This functions as the antipaladin ability, except the insinuator gains a new outsider servant each day, whose alignment must match the alignment of the outsider invoked for the day. The outsider servant functions as much as an agent for the patron invoked by the insinuator as an ally of the insinuator himself, and may turn against him if he violates his patron's alignment or interests.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-aura-of-ambition-su" data-hash-target><div className="box">Aura of Ambition (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of despair</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 8th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">Enemies within 10 feet of an insinuator take a -1 penalty on all saving throws. All allies within 10 feet gain a +1 bonus on all saving throws. This penalty does not stack with the penalty from aura of the crusader. This ability functions only while the insinuator is conscious, not if he is unconscious or dead.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-aura-of-glory-su" data-hash-target><div className="box">Aura of Glory (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of vengeance</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Free Action</div></div><div className="abEnd"><div className="box">An insinuator can expend two uses of his <em>smite impudence</em> ability to grant the ability to <em>smite impudence</em> to all allies within 10 feet, using his bonuses. Allies must use this <em>smite impudence</em> ability before the start of the insinuator's next turn, and the bonuses last for 1 minute.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-aura-of-belief-su" data-hash-target><div className="box">Aura of Belief (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of sin</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 14th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An insinuator's weapons are treated as chaos-aligned while he invokes a chaotic outsider, law-aligned when he invokes a lawful outsider, or evil-aligned while he invokes an evil outsider. If he invokes an outsider with more than one alignment aura, the insinuator must choose during the initial invocation which alignment his weapon radiates.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-aura-of-indomitability-su" data-hash-target><div className="box">Aura of Indomitability (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of depravity</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 17th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An insinuator gains DR 10 that is bypassed by the alignment opposite of the outsider he has invoked for the day, or DR 5/- while invoking a neutral outsider.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-personal-champion-su" data-hash-target><div className="box">Personal Champion (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Unholy champion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An insinuator becomes a living embodiment of his selfish desires. His damage resistance from aura of indomitability increases to 15 (or 10 while invoking a neutral outsider). Whenever he uses <em>smite impudence,</em> he adds twice his full Charisma bonus to the attack roll and doubles his effective bonus damage gained from the smite.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">In addition, he can invoke a new outsider patron by meditating for 10 minutes.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-insinuator-ex-insinuators" data-hash-target><div className="box">Ex-Insinuators</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An insinuator who willfully commits selfless acts or engages in violence that doesn't further his own ends loses all class features (including his outsider servant, but not bonus feats or weapon, armor, and shield proficiencies). He can't progress any further in levels as an insinuator. He regains his abilities and advancement potential if he atones for his faltering ambition (see the <Link to="/spell/atonement">atonement</Link> spell). If he violates the code of conduct of his invoked outsider patron, he must similarly seek atonement from outsiders of that alignment again.</div></div></div></div>
</>};
const _iron_tyrant = {title: "Iron Tyrant", jsx: <><h2 id="arc-antipaladin-iron_tyrant-iron-tyrant">Iron Tyrant</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 4</Link><br/>Covered from head to toe in blackened armor decorated with grotesque shapes and bristling with spikes, iron tyrants make an unmistakable impression on the battlefield. These antipaladins' armor is an outward symbol of their inner power, and they are rarely seen without it. Iron tyrants seek the strength to rule over domains as unfettered despots, and depend on their armor as protection against those they have not yet cowed.</p>
<p>Most iron tyrants are orcs or half-orcs who worship the orc deities <Link to="/faith/lanishra">Lanishra</Link> (god of slavery, subjugation, and tyranny) or <Link to="/faith/varg">Varg</Link> (god of iron, siege weapons, and warfare). Though rarer, some iron tyrants belong to other races and worship <Link to="/faith/urazra">Urazra</Link> (giant god of battle, brutality, and strength) or demon lords such as <Link to="/faith/aldinach">Aldinach</Link> (She of the Six Venoms), <Link to="/faith/angazhan">Angazhan</Link> (the Ravenous King), or <Link to="/faith/izyagna">Izyagna</Link> (She of the Sevenfold Swarm).</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-iron_tyrant-iron-fist-ex" data-hash-target><div className="box">Iron Fist (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch of corruption</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An iron tyrant gains <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link> as a bonus feat. In addition, whenever the iron tyrant makes a successful attack with a gauntlet, spiked gauntlet, or armor spikes, the weapon damage is based on his level and not the weapon type, as per the <Link to="/class/warpriest">warpriest's</Link> <em>sacred weapon</em> ability.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-iron_tyrant-bonus-feats" data-hash-target><div className="box">Bonus Feats</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Cruelty</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">At 3rd level and every 3 antipaladin levels thereafter (6th, 9th, 12th, and so on), an iron tyrant gains a bonus feat in addition to those gained from normal advancement. This feat must be a <Link to="/main/combat_feat">combat feat</Link> that relates to the iron tyrant's armor or shield, such as <Link to="/feat/shield_focus">Shield Focus</Link>, or one of the <Link to="/main/feats_armor_mastery">armor mastery</Link> or <Link to="/main/feats_shield_mastery">shield mastery</Link> feats.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-iron_tyrant-unstoppable-ex" data-hash-target><div className="box">Unstoppable (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Channel negative energy</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When wearing heavy armor, an iron tyrant is not slowed by terrain that halves movement (such as dense rubble, light undergrowth, and shallow bogs). Terrain that has been magically manipulated to impede motion or terrain that reduces movement by more than half still affects him.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-iron_tyrant-fiendish-bond-su" data-hash-target><div className="box">Fiendish Bond (Su)</div><div className="flavor">Instead of forming a <em>fiendish bond</em> with his weapon or a servant, an iron tyrant can form a bond with his armor.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Fiendish boon</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">An iron tyrant can enhance his armor by calling upon a fiendish spirit's aid. This bond lasts for 1 minute per antipaladin level. When called, the spirit causes the armor to shed unholy light like a <Link to="/eq-misc/torch">torch</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">If a suit of bonded armor with a fiendish spirit is destroyed, the iron tyrant loses the use of this ability for 30 days, or until he gains a level, whichever comes first. During this 30-day period, the iron tyrant takes a -1 penalty on attack rolls and weapon damage rolls.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-iron_tyrant-at-5th-level" data-hash-target><div className="box">At 5th Level</div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">Once per day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>The spirit grants the armor a +1 enhancement bonus. For every 3 antipaladin levels beyond 5th, the armor gains another +1 enhancement bonus, to a maximum of +6 at 20th level. These bonuses stack with existing armor enhancement bonuses to a maximum of +5, or they can be used to add any of the following armor special abilities. Adding these special abilities consumes an amount of bonus equal to the special ability's base price modifier (or +4 for <em>unrighteous</em>), as shown below. These special abilities are added to any special abilities the armor already has, but duplicate abilities do not stack. If the armor is not magical, at least a +1 enhancement bonus must be added before any other special abilities can be added.</p>
<ul>
<li>+1: <Link to="/magic-enh/dastard">dastard</Link></li>
<li>+1: <Link to="/magic-enh/fortification">fortification (light)</Link></li>
<li>+2: <Link to="/magic-enh/spell_resistance">spell resistance 13</Link></li>
<li>+3: <Link to="/magic-enh/ghost_touch_a">ghost touch</Link></li>
<li>+3: fortification (medium)</li>
<li>+3: <Link to="/magic-enh/invulnerability">invulnerability</Link></li>
<li>+3: spell resistance 15</li>
<li>+4: spell resistance 17</li>
<li>+4: <Link to="/magic-enh/unrighteous">unrighteous</Link></li>
<li>+5: fortification (heavy)</li>
<li>+5: spell resistance 19</li>
</ul>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">The iron tyrant can use this twice a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">The iron tyrant can use this three times a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">The iron tyrant can use this four times a day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The bonus and special abilities granted by the spirit are determined when the spirit is called and cannot be changed until the spirit is called again. The fiendish spirit imparts no bonuses if the armor is worn by anyone other than the iron tyrant, but it resumes giving bonuses if the iron tyrant dons the armor again.</div></div></div></div>
</>};
const _knight_of_the_sepulcher = {title: "Knight of the Sepulcher", jsx: <><h2 id="arc-antipaladin-knight_of_the_sepulcher-knight-of-the-sepulcher">Knight of the Sepulcher</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 64</Link><br/>Not content with the antipaladin's mere corruption of the soul, the knight of the sepulcher sacrifices mortality along with morality.</p>
<p>The knight of the sepulcher archetype is available only to the antipaladin alternate class.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-touch-of-the-crypt-ex" data-hash-target><div className="box">Touch of the Crypt (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Fiendish boon</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A knight of the sepulcher gains a +2 bonus on saving throws against mind-affecting effects, death effects, and poison. He is harmed by positive energy effects and healed by negative energy effects as though he were undead, although negative energy effects that don't heal undead (such as <Link to="/spell/enervation">enervation</Link>) affect him normally. The knight of the sepulcher has a 25% chance of ignoring critical hits and the bonus damage from <Link to="/ability/sneak_attack">sneak attacks</Link> as though he were wearing armor of <Link to="/magic-enh/light_fortification">light fortification</Link>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-fortitude-of-the-crypt-ex" data-hash-target><div className="box">Fortitude of the Crypt (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of despair</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 8th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A knight of the sepulcher gains immunity to poison. He also gains darkvision 60 feet if he does not already possess it.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-cloak-of-the-crypt-ex" data-hash-target><div className="box">Cloak of the Crypt (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The smite good use gained at 10th level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 10th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">The knight of the sepulcher gains immunity to energy drain and harmful negative energy effects. His chance of ignoring critical hits and sneak attacks increases to 50%, as though he were wearing armor of <Link to="/magic-enh/moderate_fortification">moderate fortification</Link>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-will-of-the-crypt-ex" data-hash-target><div className="box">Will of the Crypt (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of vengeance</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A knight of the sepulcher's bonus on saving throws against mind-affecting effects and death effects increases to +4.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-weapons-of-sin-su" data-hash-target><div className="box">Weapons of Sin (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of sin</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 14th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A knight of the sepulcher's weapons are treated as evil-aligned for the purposes of overcoming damage reduction.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-crypt-lord-ex" data-hash-target><div className="box">Crypt Lord (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Cruelty</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 15th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A knight of the sepulcher's chance of ignoring critical hits and sneak attacks increases to 75%, as though he were wearing armor of <Link to="/magic-enh/heavy_fortification">heavy fortification</Link>. He gains immunity to death effects, paralysis, sleep effects, and stunning. He no longer sleeps. The knight of the sepulcher also gains immunity to effects that cause fatigue, and effects that would cause him to become <Link to="/misc/exhausted">exhausted</Link> instead cause him to become <Link to="/misc/fatigued">fatigued</Link>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-soul-of-the-crypt-su" data-hash-target><div className="box">Soul of the Crypt (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of depravity</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 17th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A knight of the sepulcher gains DR 5/bludgeoning and good.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-knight_of_the_sepulcher-undying-champion-ex" data-hash-target><div className="box">Undying Champion (Ex)</div><div className="flavor">A knight of the sepulcher joins the ranks of the undead.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Unholy champion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">His DR increases to 10/bludgeoning and good. His type changes to <Link to="/type/undead">undead</Link>, and he acquires all <Link to="/umr/undead_traits">undead traits</Link>. Although immune to disease, he can still carry and spread diseases with the antipaladin's <em>plague bringer</em> ability. The undying champion no longer has a Constitution score. He uses his Charisma score for calculating hit points, Fortitude saves, and any special abilities that rely on Constitution.</div></div></div></div>
</>};
const _rough_rampager = {title: "Rough Rampager", jsx: <><h2 id="arc-antipaladin-rough_rampager-rough-rampager">Rough Rampager</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 43</Link><br/>Rough rampagers venerate <Link to="/faith/rovagug">Rovagug</Link>, reveling in the destruction the dark god represents. Where others seek power, wealth, or revenge, the rough rampager merely focuses on slaughter and mayhem. Because of their sheer destructive nature, most rough rampagers live short, brutal lives swathed in blood and carnage before someone puts them to the blade. Legends speak of dozens of rough rampagers wreaking havoc when Rovagug's spawn escape, acting as heralds and harbingers of the greater destruction created by the Rough Beast's terrifying children.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-rough_rampager-aura-of-blood-su" data-hash-target><div className="box">Aura of Blood (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of cowardice</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A rough rampager radiates a palpably daunting aura that causes all enemies within 10 feet to take a -4 penalty on Constitution or Heal checks to stop <Link to="/rule/bleed">bleed</Link> damage and checks to stabilize while <Link to="/misc/dying">dying</Link>. This ability functions only while the antipaladin is conscious.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-rough_rampager-aura-of-putrefaction-su" data-hash-target><div className="box">Aura of Putrefaction (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of despair</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 8th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A rough rampager radiates an aura that causes the wounds of enemies within 10 feet to weep blood. Injured enemies in the area take 1 point of bleed damage per round. This ability functions only while the antipaladin is conscious.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-rough_rampager-aura-of-quietus-su" data-hash-target><div className="box">Aura of Quietus (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of sin</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 14th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A rough rampager radiates an aura that causes the failure of healing spells, spell-like abilities, and supernatural abilities used to restore enemies within 10 feet of him. This is not an antimagic field, however, and ongoing or passive effects are not affected. Casters can overcome this ability with a successful caster level check versus the rough rampager's class level + 11.</div></div></div></div>
</>};
const _seal_breaker = {title: "Seal-Breaker", jsx: <><h2 id="arc-antipaladin-seal_breaker-seal-breaker">Seal-Breaker</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 43</Link><br/>Seal-breakers are dedicated to <Link to="/monster/the_whispering_tyrant">the Whispering Tyrant</Link> and have tasked themselves with finding and destroying the seals that bind him within Gallowspire. Their ties to the Whispering Tyrant give them power over undead creatures and other dark forces.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-seal_breaker-code-of-conduct" data-hash-target><div className="box">Code of Conduct</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">The seal-breaker is dedicated to releasing <Link to="/monster/the_whispering_tyrant">the Whispering Tyrant</Link> from his prison. If a sealbreaker willingly and altruistically commits a good act, he loses all class features except proficiencies. This doesn't mean that a seal-breaker can't take actions someone else might qualify as good, only that such actions must always lead toward the eventual release of the Whispering Tyrant. A seal-breaker's code requires that he place the ultimate release of Tar-Baphon above all else, as well as impose tyranny, take advantage whenever possible, and punish the good and just (provided such actions don't interfere with his ultimate goal).</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-seal_breaker-aura-of-the-grave-su" data-hash-target><div className="box">Aura of the Grave (Su)</div><div className="flavor">A seal-breaker is constantly surrounded by the chill of death.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of cowardice</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">Mindless undead within 10 feet of the seal-breaker will not attack him unless directly ordered to, and even then only after succeeding at a Will save (DC = 10 <Link to="/misc/half">half</Link> the seal-breaker's level his Charisma modifier).</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-seal_breaker-corpse-rider-su" data-hash-target><div className="box">Corpse Rider (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Fiendish boon</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A sealbreaker receives a boon from beyond the grave. This boon can take one of two forms: the seal-breaker can choose to form a bond with his weapon, or he can choose to animate an undead mount to ride.</div></div></div></div>
<div className="ability p subAbility numbered"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-seal_breaker-bonded-weapon" data-hash-target><div className="box">Bonded Weapon</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">This ability works exactly like the antipaladin's <em>fiendish boon</em> ability.</div></div></div></div>
<div className="ability p subAbility numbered"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-seal_breaker-undead-mount" data-hash-target><div className="box">Undead Mount</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The sealbreaker gains the ability to reanimate any Large corpse (or a Medium corpse for Small seal-breakers) as his corpse mount. If no such corpse is present, the seal-breaker cannot summon his mount. The corpse animates as a quadruped of the same size that the seal-breaker can ride, regardless of the corpse's living form. This corpse mount functions as a druid's <Link to="/sidekick/animal_companion">animal companion</Link> using the seal-breaker's level as his effective druid level. The mount has the same base statistics as a <Link to="/companion/horse">heavy horse</Link>, <Link to="/companion/pony">pony</Link>, <Link to="/companion/boar">boar</Link>, <Link to="/companion/camel">camel</Link>, or <Link to="/companion/dog">dog</Link> (based on its size) with the following changes: its type changes to <Link to="/type/undead">undead</Link>, it has a <Link to="/misc/good_saves">good Will save and bad Fortitude and Reflex saves</Link>, it uses the base creature's Constitution score as its Charisma score (and likewise applies all level-based advancements to Charisma instead of Constitution), and it has an Intelligence score of at least 6.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-seal_breaker-aura-of-death-su" data-hash-target><div className="box">Aura of Death (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of despair</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 8th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A seal-breaker radiates an aura that causes undead creatures within 10 feet to gain a profane bonus on all saving throws.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-seal_breaker-aura-of-rebirth-su" data-hash-target><div className="box">Aura of Rebirth (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Aura of vengeance</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">If a living creature is slain within 10 feet of the seal-breaker, the seal-breaker can spend two uses of his <em>smite good</em> ability at the start of his next turn to summon the spirit of a dead murderer to reanimate the corpse as a <Link to="/monster/mohrg">mohrg</Link>. The mohrg immediately rises and attacks the seal breaker's foes, acting under the antipaladin's command. After 1 minute, the murderer's soul leaves the body, which collapses, again lifeless.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">The seal-breaker can activate this ability as a <strong className="hl">move action</strong>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">He can activate this ability as a <strong className="hl">swift action</strong>.</div></div></div></div>
</>};
const _tyrant = {title: "Tyrant", jsx: <><h2 id="arc-antipaladin-tyrant-tyrant">Tyrant</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 64</Link><br/>Evil arises in every form imaginable, not just in hearts full of destruction and chaos. Tyrants are manipulative and lawful antipaladins, chess masters who arrange things behind the scenes to ensure that whatever happens, evil always wins, and the tyrant along with it. Unlike other antipaladins, tyrants are all too happy to associate with good creatures, the better to manipulate them into performing evil acts.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-tyrant-tyrants-code" data-hash-target><div className="box">Tyrant's Code</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Code of conduct and associated abilities, ex-antipaladins</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A tyrant must be of lawful evil alignment and loses all class features except proficiencies if he willingly and altruistically commits good acts. This does not mean the tyrant can't take actions someone else might qualify as good, only that such actions must always be in service of his own dark ambitions. A tyrant's code requires that he place his own sinister goals above all else, respect rightful authority even as he twists its loopholes to his own ends, impose tyranny, and punish all those who dare dissent. A tyrant can accept underlings of any alignment; he cares not who serves him, only that they are truly loyal to him. He can even work alongside good-aligned individuals, as long as he is secretly manipulating them.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-tyrant-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/diplomacy">Diplomacy</Link> (CHA)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Removed Skills</div></div><div className="abEnd"><div className="box">Ride</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-antipaladin-tyrant-diabolic-boon-sp" data-hash-target><div className="box">Diabolic Boon (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Fiendish boon</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">If a tyrant chooses to gain the services of a fiendish servant with his <em>fiendish boon</em> ability, he must choose a <Link to="/template/fiendish">fiendish</Link> animal or a creature with the lawful and evil subtypes.</div></div></div></div>
</>};
export default {blighted_myrmidon:_blighted_myrmidon,dread_vanguard:_dread_vanguard,fearmonger:_fearmonger,insinuator:_insinuator,iron_tyrant:_iron_tyrant,knight_of_the_sepulcher:_knight_of_the_sepulcher,rough_rampager:_rough_rampager,seal_breaker:_seal_breaker,tyrant:_tyrant}